namespace sv_f6144bbba14947ed8efd2c5220ee514a.Services;

public enum Severity { Info, Warning, Critical }

public class NotificationItem
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public Severity Severity { get; set; }
    public bool IsRead { get; set; }
    public DateTime Timestamp { get; set; }
}

/// <summary>
/// Scoped service — one instance per circuit, so each user gets independent state.
/// Components subscribe to OnChange to re-render when notifications mutate.
/// </summary>
public class NotificationService
{
    private readonly List<NotificationItem> _notifications = new();
    private int _nextId = 1;

    public event Action? OnChange;

    public IReadOnlyList<NotificationItem> All => _notifications.AsReadOnly();

    public int UnreadCount => _notifications.Count(n => !n.IsRead);

    public IReadOnlyList<NotificationItem> RecentUnread(int count) =>
        _notifications.Where(n => !n.IsRead)
                      .OrderByDescending(n => n.Timestamp)
                      .Take(count)
                      .ToList();

    public void Add(string title, Severity severity)
    {
        _notifications.Insert(0, new NotificationItem
        {
            Id = _nextId++,
            Title = title,
            Severity = severity,
            Timestamp = DateTime.UtcNow
        });
        NotifyStateChanged();
    }

    public void MarkAsRead(int id)
    {
        var item = _notifications.FirstOrDefault(n => n.Id == id);
        if (item is not null)
        {
            item.IsRead = true;
            NotifyStateChanged();
        }
    }

    public void Dismiss(int id)
    {
        _notifications.RemoveAll(n => n.Id == id);
        NotifyStateChanged();
    }

    public void MarkAllRead()
    {
        foreach (var n in _notifications)
            n.IsRead = true;
        NotifyStateChanged();
    }

    private void NotifyStateChanged() => OnChange?.Invoke();
}

@using sv_f6144bbba14947ed8efd2c5220ee514a.Services
@inject NotificationService Notifications
@implements IDisposable

<div class="nav-item px-3">
    <NavLink class="nav-link" href="notifications">
        <span class="bi bi-bell-nav-menu" aria-hidden="true"></span>
        Notifications
        @if (Notifications.UnreadCount > 0)
        {
            <span class="badge bg-danger ms-1">@Notifications.UnreadCount</span>
        }
    </NavLink>
</div>

@code {
    protected override void OnInitialized()
    {
        Notifications.OnChange += HandleChange;
    }

    private async void HandleChange()
    {
        await InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        Notifications.OnChange -= HandleChange;
    }
}

@page "/notifications"
@rendermode InteractiveServer
@using sv_f6144bbba14947ed8efd2c5220ee514a.Services
@inject NotificationService NotificationSvc
@implements IDisposable

<PageTitle>Notifications</PageTitle>

<h3>Notifications</h3>

<button class="btn btn-sm btn-outline-primary mb-3" @onclick="NotificationSvc.MarkAllRead">
    Mark All Read
</button>

@if (NotificationSvc.All.Count == 0)
{
    <p class="text-muted">No notifications.</p>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Id</th>
                <th>Title</th>
                <th>Severity</th>
                <th>Read</th>
                <th>Timestamp</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var n in NotificationSvc.All)
            {
                <tr class="@(n.IsRead ? "" : "fw-bold")">
                    <td>@n.Id</td>
                    <td>@n.Title</td>
                    <td>
                        <span class="badge @SeverityBadge(n.Severity)">@n.Severity</span>
                    </td>
                    <td>@(n.IsRead ? "Yes" : "No")</td>
                    <td>@n.Timestamp.ToString("g")</td>
                    <td>
                        @if (!n.IsRead)
                        {
                            <button class="btn btn-sm btn-outline-success me-1"
                                    @onclick="() => NotificationSvc.MarkAsRead(n.Id)">
                                Read
                            </button>
                        }
                        <button class="btn btn-sm btn-outline-danger"
                                @onclick="() => NotificationSvc.Dismiss(n.Id)">
                            Dismiss
                        </button>
                    </td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    protected override void OnInitialized()
    {
        NotificationSvc.OnChange += HandleChange;
    }

    private async void HandleChange()
    {
        await InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        NotificationSvc.OnChange -= HandleChange;
    }

    private static string SeverityBadge(Severity s) => s switch
    {
        Severity.Info => "bg-info",
        Severity.Warning => "bg-warning text-dark",
        Severity.Critical => "bg-danger",
        _ => "bg-secondary"
    };
}

