    {
        NotificationSvc.OnChange += HandleChange;

        _timer = new Timer(_ =>
        {
            var title = SampleTitles[_counter % SampleTitles.Length];
            var severity = (Severity)(_counter % 3);
            NotificationSvc.Add(title, severity);
            _counter++;
        }, null, TimeSpan.FromSeconds(15), TimeSpan.FromSeconds(15));
    }

    private async void HandleChange()
    {
        await InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        _timer?.Dispose();
        NotificationSvc.OnChange -= HandleChange;
    }

    private static string SeverityBadge(Severity s) => s switch
    {
        Severity.Info => "bg-info",
        Severity.Warning => "bg-warning text-dark",
        Severity.Critical => "bg-danger",
        _ => "bg-secondary"
    };
}

