namespace sv_f6144bbba14947ed8efd2c5220ee514a.Services;

public enum Severity { Info, Warning, Critical }

public class NotificationItem
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public Severity Severity { get; set; }
    public bool IsRead { get; set; }
    public DateTime Timestamp { get; set; }
}

/// <summary>
/// Scoped service — one instance per circuit, so each user gets independent state.
/// Components subscribe to OnChange to re-render when notifications mutate.
/// </summary>
public class NotificationService
{
    private readonly List<NotificationItem> _notifications = new();
    private int _nextId = 1;

    public event Action? OnChange;

    public IReadOnlyList<NotificationItem> All => _notifications.AsReadOnly();

    public int UnreadCount => _notifications.Count(n => !n.IsRead);

    public IReadOnlyList<NotificationItem> RecentUnread(int count) =>
        _notifications.Where(n => !n.IsRead)
                      .OrderByDescending(n => n.Timestamp)
                      .Take(count)
                      .ToList();

    public void Add(string title, Severity severity)
    {
        _notifications.Insert(0, new NotificationItem
        {
            Id = _nextId++,
            Title = title,
            Severity = severity,
            Timestamp = DateTime.UtcNow
        });
        NotifyStateChanged();
    }

    public void MarkAsRead(int id)
    {
        var item = _notifications.FirstOrDefault(n => n.Id == id);
        if (item is not null)
        {
            item.IsRead = true;
            NotifyStateChanged();
        }
    }

    public void Dismiss(int id)
    {
        _notifications.RemoveAll(n => n.Id == id);
        NotifyStateChanged();
    }

    public void MarkAllRead()
    {
        foreach (var n in _notifications)
            n.IsRead = true;
        NotifyStateChanged();
    }

    private void NotifyStateChanged() => OnChange?.Invoke();
}

